package testutils

import (
	"bytes"
	"os"
	"os/exec"
	"path/filepath"
	"runtime"
	"sync"
	"testing"
)

// NewFixtureRepo creates a clean ddx-initialized git repo for the test under
// a temp dir, registers t.Cleanup, and returns the project path. profile must
// be one of: "minimal", "standard", "multi-project", "federated" (matches
// scripts/build-fixture-repo.sh). For multi-project / federated profiles the
// returned path is the parent dir; sub-projects live underneath (proj-a,
// proj-b / hub, spoke).
//
// The helper invokes scripts/build-fixture-repo.sh and points it at a ddx
// binary built lazily once per test process from this repo's cli/ module
// (override with DDX_BIN env var).
func NewFixtureRepo(t *testing.T, profile string) string {
	t.Helper()

	root := repoRoot(t)
	script := filepath.Join(root, "scripts", "build-fixture-repo.sh")
	if _, err := os.Stat(script); err != nil {
		t.Fatalf("fixture script not found at %s: %v", script, err)
	}

	dest := t.TempDir()
	bin := resolveDDxBinary(t, root)

	cmd := exec.Command("bash", script, dest, "--profile", profile)
	cmd.Env = append(os.Environ(), "DDX_BIN="+bin)
	var stderr bytes.Buffer
	cmd.Stderr = &stderr
	cmd.Stdout = &stderr
	if err := cmd.Run(); err != nil {
		t.Fatalf("build-fixture-repo.sh failed (profile=%s): %v\n%s", profile, err, stderr.String())
	}

	// t.TempDir() handles removal; nothing else to clean up.
	return dest
}

// repoRoot walks up from this file's location to find the directory holding
// scripts/build-fixture-repo.sh.
func repoRoot(t *testing.T) string {
	t.Helper()
	_, file, _, ok := runtime.Caller(0)
	if !ok {
		t.Fatal("runtime.Caller failed")
	}
	dir := filepath.Dir(file)
	for {
		if _, err := os.Stat(filepath.Join(dir, "scripts", "build-fixture-repo.sh")); err == nil {
			return dir
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			t.Fatal("could not locate repo root from " + file)
		}
		dir = parent
	}
}

var (
	ddxBuildOnce sync.Once
	ddxBuildPath string
	ddxBuildErr  error
)

// ResolveDDxBinary is the exported variant of resolveDDxBinary. Tests outside
// this package that need the ddx binary path (e.g. integration tests that
// spawn `ddx work`) call this so the lazily-built binary is shared across
// the test process.
func ResolveDDxBinary(t *testing.T) string {
	t.Helper()
	return resolveDDxBinary(t, repoRoot(t))
}

// resolveDDxBinary returns the ddx binary path the script should use:
//   - $DDX_BIN if set,
//   - else `ddx` from PATH if available,
//   - else a binary built once per test process from <repoRoot>/cli.
func resolveDDxBinary(t *testing.T, root string) string {
	t.Helper()
	if env := os.Getenv("DDX_BIN"); env != "" {
		return env
	}
	if path, err := exec.LookPath("ddx"); err == nil {
		return path
	}

	ddxBuildOnce.Do(func() {
		dir, err := os.MkdirTemp("", "ddx-fixture-bin-")
		if err != nil {
			ddxBuildErr = err
			return
		}
		out := filepath.Join(dir, "ddx")
		cmd := exec.Command("go", "build", "-o", out, ".")
		cmd.Dir = filepath.Join(root, "cli")
		var stderr bytes.Buffer
		cmd.Stderr = &stderr
		if err := cmd.Run(); err != nil {
			ddxBuildErr = err
			ddxBuildPath = stderr.String()
			return
		}
		ddxBuildPath = out
	})
	if ddxBuildErr != nil {
		t.Fatalf("could not build ddx binary for fixture: %v\n%s", ddxBuildErr, ddxBuildPath)
	}
	return ddxBuildPath
}

package testutils

import (
	"os"
	"path/filepath"
	"testing"

	"github.com/stretchr/testify/require"
)

// TestEnvironment provides isolated test environment
type TestEnvironment struct {
	t           *testing.T
	origHome    string
	origDir     string
	tempHome    string
	tempWorkDir string
}

// NewTestEnvironment creates a new isolated test environment
func NewTestEnvironment(t *testing.T) *TestEnvironment {
	origHome := os.Getenv("HOME")
	origDir, err := os.Getwd()
	require.NoError(t, err)

	tempHome := t.TempDir()
	tempWorkDir := t.TempDir()

	env := &TestEnvironment{
		t:           t,
		origHome:    origHome,
		origDir:     origDir,
		tempHome:    tempHome,
		tempWorkDir: tempWorkDir,
	}

	// Set up isolated environment
	t.Setenv("HOME", tempHome)
	// Don't change working directory - use absolute paths instead

	return env
}

// Cleanup restores the original environment
func (env *TestEnvironment) Cleanup() {
	// Restore original environment
	if env.origHome != "" {
		_ = os.Setenv("HOME", env.origHome)
	}
	// Working directory doesn't need restoration since we never changed it
}

// HomeDir returns the temporary home directory
func (env *TestEnvironment) HomeDir() string {
	return env.tempHome
}

// WorkDir returns the temporary work directory
func (env *TestEnvironment) WorkDir() string {
	return env.tempWorkDir
}

// CreateFile creates a file with given content in the work directory
func (env *TestEnvironment) CreateFile(relPath, content string) string {
	fullPath := filepath.Join(env.tempWorkDir, relPath)
	require.NoError(env.t, os.MkdirAll(filepath.Dir(fullPath), 0755))
	require.NoError(env.t, os.WriteFile(fullPath, []byte(content), 0644))
	return fullPath
}

// CreateHomeFile creates a file with given content in the home directory
func (env *TestEnvironment) CreateHomeFile(relPath, content string) string {
	fullPath := filepath.Join(env.tempHome, relPath)
	require.NoError(env.t, os.MkdirAll(filepath.Dir(fullPath), 0755))
	require.NoError(env.t, os.WriteFile(fullPath, []byte(content), 0644))
	return fullPath
}

// CreateTemplate creates a template structure in the DDx templates directory
func (env *TestEnvironment) CreateTemplate(name string, files map[string]string) {
	templateDir := filepath.Join(env.tempHome, ".ddx", "templates", name)
	require.NoError(env.t, os.MkdirAll(templateDir, 0755))

	for relPath, content := range files {
		fullPath := filepath.Join(templateDir, relPath)
		require.NoError(env.t, os.MkdirAll(filepath.Dir(fullPath), 0755))
		require.NoError(env.t, os.WriteFile(fullPath, []byte(content), 0644))
	}
}

// CreateConfig creates a .ddx.yml config file in the work directory
func (env *TestEnvironment) CreateConfig(content string) {
	env.CreateFile(".ddx.yml", content)
}

// CreateGlobalConfig creates a global .ddx.yml config file
func (env *TestEnvironment) CreateGlobalConfig(content string) {
	env.CreateHomeFile(".ddx.yml", content)
}

// AssertFileExists asserts that a file exists relative to work directory
func (env *TestEnvironment) AssertFileExists(t *testing.T, relPath string) {
	fullPath := filepath.Join(env.tempWorkDir, relPath)
	require.FileExists(t, fullPath)
}

// AssertFileContent asserts file content matches expected
func (env *TestEnvironment) AssertFileContent(t *testing.T, relPath, expected string) {
	fullPath := filepath.Join(env.tempWorkDir, relPath)
	content, err := os.ReadFile(fullPath)
	require.NoError(t, err)
	require.Equal(t, expected, string(content))
}

package workerprobe_test

import (
	"bufio"
	"encoding/json"
	"net/http/httptest"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"testing"
	"time"

	serverpkg "github.com/DocumentDrivenDX/ddx/internal/server"
	"github.com/DocumentDrivenDX/ddx/internal/testutils"
)

// TestWorker_RealAttemptEvents_FlowToServer is the wired-in end-to-end
// proof for ADR-022 step 2: it stands up the production server HTTP path
// (httptest.Server wrapping a real serverpkg.Server), points the worker at
// it via the production server.addr discovery (XDG_DATA_HOME), spawns a
// real `ddx work --once` subprocess against a fixture project, and
// asserts that the worker's bead-attempt loop events appear in the
// server's derived view (the worker-events.jsonl log) within 5s.
//
// This exercises the entire wire: writeLoopEvent ÔåÆ loopSink ÔåÆ TeeJSONL ÔåÆ
// workerprobe.Probe ÔåÆ POST /api/workers/register + /api/workers/{id}/event
// (or /backfill on the immediate first probe before any events fire).
func TestWorker_RealAttemptEvents_FlowToServer(t *testing.T) {
	if testing.Short() {
		t.Skip("integration test: spawns ddx work subprocess")
	}

	// Use a 'standard' fixture (5 sample beads) so the loop has at least
	// one bead to claim ÔåÆ at least one bead-scoped event flows. We don't
	// require the bead to succeed; ddx work will emit loop.start +
	// bead.claimed before any harness invocation.
	// Build a fresh ddx binary from the current tree so the subprocess
	// includes the workerprobe wiring under test (cannot rely on $PATH ddx
	// being current). Build before NewFixtureRepo so the same binary seeds
	// the fixture, avoiding two builds.
	binDir := t.TempDir()
	binPath := filepath.Join(binDir, "ddx")
	build := exec.Command("go", "build", "-o", binPath, ".")
	build.Dir = repoCLIDir(t)
	if out, err := build.CombinedOutput(); err != nil {
		t.Fatalf("go build ddx: %v\n%s", err, out)
	}
	t.Setenv("DDX_BIN", binPath)

	proj := testutils.NewFixtureRepo(t, "standard")
	bin := binPath

	// Real server ÔÇö same constructor, same Handler, same requireTrusted gate.
	srv := serverpkg.New(":0", proj)
	ts := httptest.NewServer(srv.Handler())
	defer ts.Close()

	// Production discovery path: write server.addr under XDG_DATA_HOME so
	// the worker subprocess (running with the same XDG_DATA_HOME) finds it
	// via serverpkg.ReadServerAddr.
	xdg := t.TempDir()
	addrDir := filepath.Join(xdg, "ddx")
	if err := os.MkdirAll(addrDir, 0o700); err != nil {
		t.Fatalf("mkdir addr dir: %v", err)
	}
	addrPath := filepath.Join(addrDir, "server.addr")
	addrPayload, _ := json.Marshal(map[string]any{
		"url": ts.URL,
		"pid": os.Getpid(), // alive so ReadServerAddr accepts it
	})
	if err := os.WriteFile(addrPath, addrPayload, 0o600); err != nil {
		t.Fatalf("write server.addr: %v", err)
	}

	// Spawn `ddx work --once`. We deliberately pass --no-review and
	// a bogus harness so the worker exits quickly after emitting loop.start
	// + bead.claimed; the harness failure is irrelevant to this test, which
	// asserts only that events flowed through the probe.
	cmd := exec.Command(bin, "work", "--once", "--no-review",
		"--harness", "noop", "--poll-interval", "0", "--project", proj)
	cmd.Env = append(os.Environ(),
		"XDG_DATA_HOME="+xdg,
		"HOME="+t.TempDir(),
	)
	cmd.Dir = proj
	out, err := cmd.CombinedOutput()
	t.Logf("ddx work exit: err=%v\noutput:\n%s", err, out)

	// Wait up to 5s for the server's worker-events.jsonl log to receive at
	// least one event mirrored from the worker subprocess.
	logPath := filepath.Join(proj, ".ddx", "server", "worker-events.jsonl")
	deadline := time.Now().Add(5 * time.Second)
	var lines []string
	for time.Now().Before(deadline) {
		lines = readLogLines(t, logPath)
		if len(lines) > 0 {
			break
		}
		time.Sleep(50 * time.Millisecond)
	}
	if len(lines) == 0 {
		t.Fatalf("no worker events appeared in %s within 5s; subprocess output:\n%s", logPath, out)
	}

	// Sanity-check: at least one mirrored event should be a loop.* or
	// bead.* envelope identifiable by the writeLoopEvent shape (kind field
	// in the loggedEvent wrapper).
	var kinds []string
	for _, line := range lines {
		var le struct {
			Kind string `json:"kind"`
		}
		_ = json.Unmarshal([]byte(line), &le)
		kinds = append(kinds, le.Kind)
	}
	t.Logf("mirrored event kinds: %v", kinds)
	hasExpected := false
	for _, k := range kinds {
		if strings.HasPrefix(k, "loop.") || strings.HasPrefix(k, "bead.") {
			hasExpected = true
			break
		}
	}
	if !hasExpected {
		t.Errorf("expected at least one loop.* or bead.* event mirrored, got kinds=%v", kinds)
	}
}

// repoCLIDir walks up from this file to find the cli/ directory (which
// holds go.mod). Used to build a fresh ddx binary for the integration test.
func repoCLIDir(t *testing.T) string {
	t.Helper()
	wd, err := os.Getwd()
	if err != nil {
		t.Fatalf("getwd: %v", err)
	}
	dir := wd
	for {
		if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
			return dir
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			t.Fatalf("could not locate go.mod from %s", wd)
		}
		dir = parent
	}
}

// readLogLines returns each newline-separated line of the file at path,
// or nil if the file does not yet exist.
func readLogLines(t *testing.T, path string) []string {
	t.Helper()
	f, err := os.Open(path)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		t.Fatalf("open %s: %v", path, err)
	}
	defer f.Close()
	var out []string
	sc := bufio.NewScanner(f)
	for sc.Scan() {
		out = append(out, sc.Text())
	}
	return out
}

package server

// LAYER 1 of the GraphQL multi-project leak fix (ddx-4c51d33e).
// Verifies the scoped /api/projects/{project}/graphql endpoint isolates
// resolver WorkingDir per request, and that the legacy /graphql route
// continues to serve the server's startup project.

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"os"
	"path/filepath"
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/testutils"
)

// seedDocsProject creates a temp project rooted at root with a single
// docgraph-tracked markdown document carrying the given DDx id and title.
// Returns the absolute project path and the document's relative path.
func seedDocsProject(t *testing.T, root, name, docID, title string) (string, string) {
	t.Helper()
	projectPath := filepath.Join(root, name)
	if err := os.MkdirAll(filepath.Join(projectPath, ".ddx"), 0o755); err != nil {
		t.Fatal(err)
	}
	cfg := `version: "1.0"
library:
  path: ".ddx/plugins/ddx"
  repository:
    url: "https://example.com/lib"
    branch: "main"
`
	if err := os.WriteFile(filepath.Join(projectPath, ".ddx", "config.yaml"), []byte(cfg), 0o644); err != nil {
		t.Fatal(err)
	}
	docsDir := filepath.Join(projectPath, "docs")
	if err := os.MkdirAll(docsDir, 0o755); err != nil {
		t.Fatal(err)
	}
	relPath := filepath.Join("docs", docID+".md")
	body := "---\nddx:\n  id: " + docID + "\n---\n# " + title + "\n\nbody for " + docID + "\n"
	if err := os.WriteFile(filepath.Join(projectPath, relPath), []byte(body), 0o644); err != nil {
		t.Fatal(err)
	}
	return projectPath, relPath
}

// postGraphQL fires a POST against the given path on srv and returns the
// response recorder. Sets RemoteAddr so isTrusted() accepts the request.
func postGraphQL(t *testing.T, srv *Server, path, query string) *httptest.ResponseRecorder {
	t.Helper()
	body, _ := json.Marshal(map[string]string{"query": query})
	req := httptest.NewRequest(http.MethodPost, path, bytes.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	req.RemoteAddr = "127.0.0.1:12345"
	w := httptest.NewRecorder()
	srv.Handler().ServeHTTP(w, req)
	return w
}

// TestGraphQL_ScopedRoute_DocumentByPath_OnlyReturnsScopedProjectDocs is
// AC #5 of ddx-4c51d33e: a query against project B's scoped GraphQL endpoint
// must read project B's documents, not the server's startup project (A).
func TestGraphQL_ScopedRoute_DocumentByPath_OnlyReturnsScopedProjectDocs(t *testing.T) {
	t.Setenv("XDG_DATA_HOME", t.TempDir())
	t.Setenv("DDX_NODE_NAME", "gql-scope-test")

	root := t.TempDir()
	projA, relA := seedDocsProject(t, root, "proj-a", "alpha", "Alpha A")
	projB, relB := seedDocsProject(t, root, "proj-b", "beta", "Beta B")

	srv := New(":0", projA)
	t.Cleanup(func() { _ = srv.Shutdown() })
	entryB := srv.state.RegisterProject(projB)

	// 1. Hit the scoped endpoint for project B asking for B's document by path.
	queryB := `{ documentByPath(path: "` + filepath.ToSlash(relB) + `") { id path content } }`
	w := postGraphQL(t, srv, "/api/projects/"+entryB.ID+"/graphql", queryB)
	if w.Code != http.StatusOK {
		t.Fatalf("scoped B query: status=%d body=%s", w.Code, w.Body.String())
	}
	var resp struct {
		Data struct {
			DocumentByPath *struct {
				ID      string  `json:"id"`
				Path    string  `json:"path"`
				Content *string `json:"content"`
			} `json:"documentByPath"`
		} `json:"data"`
		Errors []map[string]any `json:"errors"`
	}
	if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
		t.Fatalf("decode resp: %v body=%s", err, w.Body.String())
	}
	if len(resp.Errors) != 0 {
		t.Fatalf("scoped B query errors: %v", resp.Errors)
	}
	if resp.Data.DocumentByPath == nil {
		t.Fatalf("scoped B query: documentByPath is null, expected B's document")
	}
	if resp.Data.DocumentByPath.Content == nil || !strings.Contains(*resp.Data.DocumentByPath.Content, "Beta B") {
		t.Fatalf("scoped B query: expected B's content, got %+v", resp.Data.DocumentByPath)
	}

	// 2. Asking the scoped B endpoint for A's document path must NOT find it
	//    (resolves to null since A's doc does not exist under B's project root).
	queryAOnB := `{ documentByPath(path: "` + filepath.ToSlash(relA) + `") { id path content } }`
	w2 := postGraphQL(t, srv, "/api/projects/"+entryB.ID+"/graphql", queryAOnB)
	if w2.Code != http.StatusOK {
		t.Fatalf("cross-project leak query: status=%d body=%s", w2.Code, w2.Body.String())
	}
	var resp2 struct {
		Data struct {
			DocumentByPath *struct {
				ID      string  `json:"id"`
				Content *string `json:"content"`
			} `json:"documentByPath"`
		} `json:"data"`
	}
	_ = json.Unmarshal(w2.Body.Bytes(), &resp2)
	if resp2.Data.DocumentByPath != nil {
		// If non-null and content contains A's title, that's the leak we're
		// guarding against. The naming `relA` happens to equal `relB` so this
		// also implicitly proves we're not reading from project A's filesystem.
		if resp2.Data.DocumentByPath.Content != nil && strings.Contains(*resp2.Data.DocumentByPath.Content, "Alpha A") {
			t.Fatalf("CROSS-PROJECT LEAK: scoped B endpoint returned A's content: %+v", resp2.Data.DocumentByPath)
		}
	}
}

// TestGraphQL_ScopedRoute_RejectsUnregisteredProject is AC #6: the scoped
// route must 404 when the path's project segment doesn't resolve.
func TestGraphQL_ScopedRoute_RejectsUnregisteredProject(t *testing.T) {
	t.Setenv("XDG_DATA_HOME", t.TempDir())
	t.Setenv("DDX_NODE_NAME", "gql-scope-404-test")

