func (s *ServerState) GetProjectByPath(path string) (ProjectEntry, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	for _, p := range s.Projects {
		if p.Path == path {
			return p, true
		}
	}
	return ProjectEntry{}, false
